/* Assuming 'MyColorFont' is a COLR v1 or SVG font that includes predefined palettes like 'light', 'dark', 'vibrant', 'corporate' */
@font-face {
  font-family: 'MyColorFont';
  src: url('my-color-font.woff2') format('woff2-COLR');
  /* The browser might default to a specific palette if not explicitly set here,
     or the font author might define a default. */
}

body {
  font-family: 'MyColorFont', sans-serif;
  /* Apply a specific named palette defined within the font */
  font-palette: dark;
}

.heading {
  /* Switch to another palette for specific elements */
  font-palette: vibrant;
  font-size: 3em;
  line-height: 1.1;
}

.footer-text {
  /* Use yet another palette */
  font-palette: corporate;
  font-size: 0.9em;
  opacity: 0.8;
}

/* Example for dark mode adaptation (if palettes are defined within the font) */
@media (prefers-color-scheme: dark) {
  body {
    font-palette: dark-mode-optimized; /* Or just 'dark' if it's generic */
  }
}
